function trackAwfEvent(
  eventName: string,
  parameters: Record<string, unknown> = {},
) {
  if (typeof window === "undefined") return;

  (window as any).gtag?.("event", eventName, {
    event_category: "A Wealthy Foundation",
    ...parameters,
  });
}

